effect.shader:
void main() {

    vec2 texelSize = 1.0 / getTexSize(inputImg.size);
    float Radius = radius;
    float T = strength;

    vec2 UV = acScreenNorm;

    vec2 CENTER = centerPoint*vec2(-1,-1);

    vec2 diff1 = acLayerCenter-CENTER;
    diff1.y = acScreenSize.y - diff1.y;
    vec2 diff = diff1 /acScreenSize;

    UV -= diff;
    vec2 convRate = vec2(1,1);
    if(acScreenSize.y > acScreenSize.x)
        convRate.y=(acScreenSize.y/acScreenSize.x);
    else
        convRate.x=(acScreenSize.x/acScreenSize.y);
    UV *= convRate;

    float Dist = length(UV);

    vec4 color = vec4(0.0);

    if ( Dist < Radius )
    {
        float speed = 0.0;
        float localPower = (Radius - Dist) / Radius;
        {
          float A = ( T <= 0.5 ) ? mix( 0.0, 1.0, T/0.5 ) : mix( 1.0, 0.0, (T-0.5)/0.5 );
          float Theta = localPower * localPower * A * 8.0 * 3.14159;
          float l = Dist * Theta;
          speed = abs(l/texelSize.x*10.0);
        }
        float nSamples = float(clamp(speed, 1.01, 2000.01));

        vec2 v = UV/nSamples;
        vec2 c = vec2(0.0);
        float count = 0.0;
        for(float d = max(Radius - abs(strength)*localPower, Dist); d <= Radius; d += 1.0/nSamples) {
            float Percent = (Radius - d) / Radius;
            vec2 cc = UV - c;
            c += v;
            float A = ( T <= 0.5 ) ? mix( 0.0, 1.0, T/0.5 ) : mix( 1.0, 0.0, (T-0.5)/0.5 );
            float Theta = Percent * Percent * A * 8.0 * 3.14159;
            float S = sin( Theta );
            float C = cos( Theta );
            vec2 res = vec2( dot(cc, vec2(C, -S)), dot(cc, vec2(S, C)) );
            res /= convRate;
            res += diff;
            color += texture2DCv(inputImg.texture, res);
            count += 1.0;
        }
        color /= count;
    }
    else {
        UV /= convRate;
        UV += diff;
        color = texture2DCv(inputImg.texture, UV);
    }

    gl_FragColor = color;

}
